#include "biblia.h"

void Biblia::CarregarAgeu(Biblia* b) {
    b->dados[AGEU].nome = wxT("Ageu");

    b->dados[AGEU].capitulos[1].versos[1] = wxT("No segundo ano do rei Dario, no sexto mês, no primeiro dia do mês, veio a palavra do Senhor, por intermédio do profeta Ageu, a Zorobabel, governador de Judá, filho de Sealtiel, e a Josué, o sumo sacerdote, filho de Jeozadaque, dizendo:");
    b->dados[AGEU].capitulos[1].versos[2] = wxT("Assim fala o Senhor dos exércitos, dizendo: Este povo diz: Não veio ainda o tempo, o tempo de se edificar a casa do Senhor.");
    b->dados[AGEU].capitulos[1].versos[3] = wxT("Veio, pois, a palavra do Senhor, por intermédio do profeta Ageu, dizendo:");
    b->dados[AGEU].capitulos[1].versos[4] = wxT("Acaso é tempo de habitardes nas vossas casas forradas, enquanto esta casa fica desolada?");
    b->dados[AGEU].capitulos[1].versos[5] = wxT("Ora pois, assim diz o Senhor dos exércitos: Considerai os vossos caminhos.");
    b->dados[AGEU].capitulos[1].versos[6] = wxT("Tendes semeado muito, e recolhido pouco; comeis, mas não vos fartais; bebeis, mas não vos saciais; vestis-vos, mas ninguém se aquece; e o que recebe salário, recebe-o para o meter num saco furado.");
    b->dados[AGEU].capitulos[1].versos[7] = wxT("Assim diz o Senhor dos exércitos: Considerai os vossos caminhos.");
    b->dados[AGEU].capitulos[1].versos[8] = wxT("Subi ao monte, e trazei madeira, e edificai a casa; e dela me deleitarei, e serei glorificado, diz o Senhor.");
    b->dados[AGEU].capitulos[1].versos[9] = wxT("Esperastes o muito, mas eis que veio a ser pouco; e esse pouco, quando o trouxestes para casa, eu o dissipei com um assopro. Por que causa? diz o Senhor dos exércitos. Por causa da minha casa, que está em ruínas, enquanto correis, cada um de vós, à sua própria casa.");
    b->dados[AGEU].capitulos[1].versos[10] = wxT("Por isso os céus por cima de vós retêm o orvalho, e a terra retém os seus frutos.");
    b->dados[AGEU].capitulos[1].versos[11] = wxT("E mandei vir a seca sobre a terra, e sobre as colinas, sobre o trigo e o mosto e o azeite, e sobre tudo o que a terra produz; como também sobre os homens e os animais, e sobre todo o seu trabalho.");
    b->dados[AGEU].capitulos[1].versos[12] = wxT("Então Zorobabel, filho de Sealtiel, e o sumo sacerdote Josué, filho de Jeozadaque, juntamente com todo o resto do povo, obedeceram a voz do Senhor seu Deus, e as palavras do profeta Ageu, como o Senhor seu Deus o tinha enviado; e temeu o povo diante do Senhor.");
    b->dados[AGEU].capitulos[1].versos[13] = wxT("Então Ageu, o mensageiro do Senhor, falou ao povo, conforme a mensagem do Senhor, dizendo: Eu sou convosco, e diz o Senhor.");
    b->dados[AGEU].capitulos[1].versos[14] = wxT("E o Senhor suscitou o espírito do governador de Judá Zorobabel, filho de Sealtiel, e o espírito do sumo sacerdote Josué, filho de Jeozadaque, e o espírito de todo o resto do povo; e eles vieram, e começaram a trabalhar na casa do Senhor dos exércitos, seu Deus,");
    b->dados[AGEU].capitulos[1].versos[15] = wxT("ao vigésimo quarto dia do sexto mês.");

    b->dados[AGEU].capitulos[2].versos[1] = wxT("No segundo ano do rei Dario, no sétimo mês, ao vigésimo primeiro do mês, veio a palavra do Senhor por intermédio do profeta Ageu, dizendo:");
    b->dados[AGEU].capitulos[2].versos[2] = wxT("Fala agora ao governador de Judá, Zorobabel, filho de Sealtiel, e ao sumo sacerdote Josué, filho de Jeozadaque, e ao resto do povo, dizendo:");
    b->dados[AGEU].capitulos[2].versos[3] = wxT("Quem há entre vós, dos sobreviventes, que viu esta casa na sua primeira glória? Em que estado a vedes agora? Não é como nada em vossos olhos?");
    b->dados[AGEU].capitulos[2].versos[4] = wxT("Ora, pois, esforça-te, Zorobabel, diz o Senhor, e esforça-te, sumo sacerdote Josué, filho de Jeozadaque, e esforçai-vos, todo o povo da terra, diz o Senhor, e trabalhai; porque eu sou convosco, diz o Senhor dos exércitos,");
    b->dados[AGEU].capitulos[2].versos[5] = wxT("segundo o pacto que fiz convosco, quando saístes do Egito, e o meu Espírito habita no meio de vós; não temais.");
    b->dados[AGEU].capitulos[2].versos[6] = wxT("Pois assim diz o Senhor dos exércitos; Ainda uma vez, daqui a pouco, e abalarei os céus e a terra, o mar e a terra seca.");
    b->dados[AGEU].capitulos[2].versos[7] = wxT("Abalarei todas as nações; e as coisas preciosas de todas as nações virão, e encherei de glória esta casa, diz o Senhor dos exércitos.");
    b->dados[AGEU].capitulos[2].versos[8] = wxT("Minha é a prata, e meu é o ouro, diz o Senhor dos exércitos.");
    b->dados[AGEU].capitulos[2].versos[9] = wxT("A glória desta última casa será maior do que a da primeira, diz o Senhor dos exércitos; e neste lugar darei a paz, diz o Senhor dos exércitos.");
    b->dados[AGEU].capitulos[2].versos[10] = wxT("Ao vigésimo quarto dia do mês nono, no segundo ano de Dario, veio a palavra do Senhor ao profeta Ageu, dizendo:");
    b->dados[AGEU].capitulos[2].versos[11] = wxT("Assim diz o Senhor dos exércitos: Pergunta agora aos sacerdotes, acerca da lei, dizendo:");
    b->dados[AGEU].capitulos[2].versos[12] = wxT("Se alguém levar na aba de suas vestes carne santa, e com a sua aba tocar no pão, ou no guisado, ou no vinho, ou no azeite, ou em qualquer outro mantimento, ficará este santificado? E os sacerdotes responderam: Não.");
    b->dados[AGEU].capitulos[2].versos[13] = wxT("Então perguntou Ageu: Se alguém, que for contaminado pelo contato com o corpo morto, tocar nalguma destas coisas, ficará ela imunda? E os sacerdotes responderam: Ficará imunda.");
    b->dados[AGEU].capitulos[2].versos[14] = wxT("Ao que respondeu Ageu, dizendo: Assim é este povo, e assim é esta nação diante de mim, diz o Senhor; assim é toda a obra das suas mãos; e tudo o que ali oferecem imundo é.");
    b->dados[AGEU].capitulos[2].versos[15] = wxT("Agora considerai o que acontece desde aquele dia. Antes que se lançasse pedra sobre pedra no templo do Senhor,");
    b->dados[AGEU].capitulos[2].versos[16] = wxT("quando alguém vinha a um montão de trigo de vinte medidas, havia somente dez; quando vinha ao lagar para tirar cinqüenta, havia somente vinte.");
    b->dados[AGEU].capitulos[2].versos[17] = wxT("Feri-vos com mangra, e com ferrugem, e com saraiva, em todas as obras das vossas mãos; e não houve entre vós quem voltasse para mim, diz o Senhor.");
    b->dados[AGEU].capitulos[2].versos[18] = wxT("Considerai, pois, eu vos rogo, desde este dia em diante, desde o vigésimo quarto dia do mês nono, desde o dia em que se lançaram os alicerces do templo do Senhor, sim, considerai essas coisas.");
    b->dados[AGEU].capitulos[2].versos[19] = wxT("Está ainda semente no celeiro? A videira, a figueira, a romeira, e a oliveira ainda não dão os seus frutos? Desde este dia hei de vos abençoar.");
    b->dados[AGEU].capitulos[2].versos[20] = wxT("Veio pela segunda vez a palavra do Senhor a Ageu, aos vinte e quatro do mês, dizendo:");
    b->dados[AGEU].capitulos[2].versos[21] = wxT("Fala a Zorobabel, governador de Judá, dizendo: Abalarei os céus e a terra;");
    b->dados[AGEU].capitulos[2].versos[22] = wxT("e derrubarei o trono dos reinos, e destruirei a força dos reinos das nações; destruirei o carro e os que nele andam; os cavalos e os seus cavaleiros cairão, cada um pela espada do seu irmão.");
    b->dados[AGEU].capitulos[2].versos[23] = wxT("Naquele dia, diz o Senhor dos exércitos, tomar-te-ei, ó Zorobabel, servo meu, filho de Sealtiel, diz o Senhor, e te farei como um anel de selar; porque te escolhi, diz o Senhor dos exércitos.");

}
